metadata.initialCode:
import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const marketQuery = "Will Paris Saint-Germain FC win on 2026-04-08?";

  const liquidity = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "analyze_market_liquidity",
    args: {
      marketQuery
    }
  });

  const whaleCost = liquidity.whaleCost || {};
  const sizes = {
    sell1k: whaleCost.sell1k || null,
    sell5k: whaleCost.sell5k || null,
    sell10k: whaleCost.sell10k || null
  };

  const extractSlippage = (bucket) => {
    if (!bucket || typeof bucket !== "object") return null;
    if (typeof bucket.slippagePercent === "number") return bucket.slippagePercent;
    if (typeof bucket.slippage === "number") return bucket.slippage;
    if (typeof bucket.estimatedSlippage === "number") return bucket.estimatedSlippage;
    return null;
  };

  return {
    market: liquidity.market,
    tokenId: liquidity.tokenId,
    currentPrice: liquidity.currentPrice,
    spread: liquidity.spread,
    liquidityScore: liquidity.liquidityScore,
    mergedDepth: liquidity.depth || null,
    depthWithin2Percent: liquidity.depthWithin2Percent || null,
    exitSlippage: {
      sell1k: extractSlippage(sizes.sell1k),
      sell5k: extractSlippage(sizes.sell5k),
      sell10k: extractSlippage(sizes.sell10k)
    },
    whaleCost: sizes,
    recommendation: liquidity.recommendation,
    fetchedAt: liquidity.fetchedAt
  };
}

