import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const eventQuery = "Democratic Presidential Nominee 2028";
  const targetLegs = [
    { requestedName: "Stephen A. Smith", target: "Stephen A. Smith", requiredTerms: ["Stephen", "A.", "Smith"], avoidTerms: ["Whitmer", "Oprah"] },
    { requestedName: "Gretchen Whitmer", target: "Gretchen Whitmer", requiredTerms: ["Gretchen", "Whitmer"], avoidTerms: ["Stephen", "Oprah"] },
    { requestedName: "Oprah Winfrey", target: "Oprah Winfrey", requiredTerms: ["Oprah", "Winfrey"], avoidTerms: ["Stephen", "Whitmer"] }
  ];

  const readBatch = await callMcpSkillsParallel({
    label: "democratic-nominee-2028-read-batch",
    calls: [
      {
        key: "event-outcomes",
        toolId,
        toolName: "search_and_get_outcomes",
        args: {
          query: eventQuery,
          sortBy: "volume",
          category: "politics"
        }
      },
      {
        key: "pairwise-quotes",
        toolId,
        toolName: "compare_event_outcome_quotes",
        args: {
          eventQuery,
          outcomes: targetLegs.map((x) => x.requestedName),
          includeHistory: false
        }
      }
    ]
  });

  const outcomesResult = readBatch.results.find((r) => r.key === "event-outcomes");
  const compareResult = readBatch.results.find((r) => r.key === "pairwise-quotes");

  const eventData = outcomesResult && outcomesResult.status === "fulfilled" ? outcomesResult.value : null;
  const quoteData = compareResult && compareResult.status === "fulfilled" ? compareResult.value : null;

  const searchOutcomes = Array.isArray(eventData?.outcomes) ? eventData.outcomes : [];
  const matchedOutcomes = Array.isArray(quoteData?.matchedOutcomes) ? quoteData.matchedOutcomes : [];

  const semanticSelections = targetLegs.map((leg) => {
    const candidates = [...matchedOutcomes, ...searchOutcomes].map((item) => ({
      ...item,
      name: item.matchedName || item.name || item.requestedName || ""
    }));

    const ranked = pickTopSemanticCandidates({
      target: leg.target,
      candidates,
      requiredTerms: leg.requiredTerms,
      avoidTerms: leg.avoidTerms,
      limit: 1
    });

    return {
      requestedName: leg.requestedName,
      selected: Array.isArray(ranked) && ranked.length > 0 ? ranked[0] : null
    };
  });

  const selectedByName = Object.fromEntries(
    semanticSelections.map((x) => [String(x.requestedName).toLowerCase(), x.selected])
  );

  const stephen = selectedByName["stephen a. smith"];
  const whitmer = selectedByName["gretchen whitmer"];
  const oprah = selectedByName["oprah winfrey"];

  const hasAll = Boolean(stephen && whitmer && oprah && Number.isFinite(stephen.currentPrice) && Number.isFinite(whitmer.currentPrice) && Number.isFinite(oprah.currentPrice));

  let richOrCheap = "insufficient_data";
  let relativeValue = null;

  if (hasAll) {
    const peerAvg = (Number(whitmer.currentPrice) + Number(oprah.currentPrice)) / 2;
    const diff = Number(stephen.currentPrice) - peerAvg;
    relativeValue = diff;
    richOrCheap = diff > 0.02 ? "rich" : diff < -0.02 ? "cheap" : "roughly_fair";
  }

  return {
    eventQuery,
    fetchedAt: {
      eventOutcomes: eventData?.fetchedAt || null,
      pairwiseQuotes: quoteData?.fetchedAt || null
    },
    readBatchSummary: readBatch.summary,
    semanticSelections,
    comparison: {
      richOrCheap,
      relativeValue,
      basis: hasAll
        ? "Stephen A. Smith compared against the average of Gretchen Whitmer and Oprah Winfrey currentPrice values"
        : "insufficient matched data to make a grounded relative-value judgment"
    },
    matchedQuotes: {
      stephenASmith: stephen || null,
      gretchenWhitmer: whitmer || null,
      oprahWinfrey: oprah || null
    },
    unmatchedOutcomes: Array.isArray(quoteData?.unmatchedOutcomes) ? quoteData.unmatchedOutcomes : [],
    eventTitle: quoteData?.eventTitle || eventData?.eventTitle || null
  };
}

